import '../App.js'
import '../App.css';
import img from '../img/DSC_1614.JPG';
import React, { Component, useState } from 'react';
import Cart from './Cart.js';
import Product  from './Product.js';
import data from './Data.js';

function Banner(props) {
  const [addItem,setAddItem]=useState(0)
 
const add=()=>{
  setAddItem(addItem+1)
  }
  const [addCart,setAddCart]=useState([])

  const addToCart=(data)=>{
    setAddCart(data);
    console.log(addCart.price)
  }
  
  return (
    <div className="banner">
     <>
     <section className='banner'>
      <div className="container">
        <div className='row complex'>
          <div className='col-md-8'>
          <div>
        <div className='d-flex align-items-center justify-content-between py-5'>
        <h1 >hello my name is {props.value} </h1>
        <h1>{addItem}</h1>

        </div>
  
  <div className='row'>

    {
      data.productData.map((item,index)=>{
return(
  <>
   <div className='col-md-3 py-3' >

  <Product imgValue={item.img} price={item.price}  id={item.id}/>
  <button onClick={()=>addToCart(item)}>add</button>
   </div>

  </>
  
)
      })
    }
    {/* <Product imgValue={img} price={12000} add={add} key={1}/>
    <Product imgValue={img} price={6000} add={add} key={2} />
    <Product imgValue={img} price={8000} add={add} key={3}/> */}

 
  </div>
  </div>
  </div>
  <div className='col-md-4'>
 {/* <Cart CartImg={img}/> */}
 <div>
 <Cart CartImg={addCart}/>
 </div>
  </div>
  </div>
      </div>
     </section  >
     

     
     
      </>
    </div>
  );
}

export default Banner;
